                prop_assert_eq!(
                    ctx.segments
                        .iter()
                        .find(|segment| segment.kind == DateSegmentKind::Day)
                        .and_then(|segment| segment.value),
                    Some(i32::from(value.day()))
                );
            }
        }
    }

